  1	import { Button, Flex, FlexItem, Popover, PopoverPosition, Text, TextVariants } from '@patternfly/react-core';
  2	import { TimesIcon } from '@patternfly/react-icons';
  3	import React from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import { ContextSingleton } from '../../utils/context';
  6	import { useHighLight } from '../../utils/highlight-hook';
  7	import './guided-tour.css';
  8	
  9	export type GuidedTourItem = {
 10	  title: string;
 11	  description: string;
 12	  assetName?: string;
 13	  minWidth?: string;
 14	  position?: PopoverPosition;
 15	  ref: React.RefObject<HTMLDivElement>;
 16	};
 17	
 18	export type IndexChangeFunction = (index: number | undefined) => void;
 19	
 20	export type GuidedTourHandle = {
 21	  startTour: () => void;
 22	  updateTourItems: (items: GuidedTourItem[]) => void;
 23	  addOnIndexChangeListener: (fn: IndexChangeFunction) => void;
 24	  clearOnIndexChangeListener: () => void;
 25	};
 26	
 27	export interface GuidedTourPopoverProps {
 28	  id: string;
 29	  isDark: boolean;
 30	}
 31	
 32	const onIndexChangeFunctions: IndexChangeFunction[] = [];
 33	// eslint-disable-next-line react/display-name
 34	export const GuidedTourPopover = React.forwardRef<GuidedTourHandle, GuidedTourPopoverProps>((props, ref) => {
 35	  const { t } = useTranslation('plugin__netobserv-plugin');
 36	  const isStandalone = ContextSingleton.isStandalone();
 37	  const { highlightElement, clearHighlights } = useHighLight(props.isDark);
 38	  const [items, setItems] = React.useState<GuidedTourItem[]>([]);
 39	  const [index, setIndex] = React.useState<number | undefined>();
 40	
 41	  React.useImperativeHandle(ref, () => ({
 42	    startTour,
 43	    updateTourItems,
 44	    addOnIndexChangeListener,
 45	    clearOnIndexChangeListener
 46	  }));
 47	
 48	  const startTour = () => {
 49	    setIndex(0);
 50	    if (!items.length) {
 51	      console.error('startTour called while items = ', items);
 52	    }
 53	  };
 54	
 55	  const updateTourItems = (items: GuidedTourItem[]) => {
 56	    setItems(items);
 57	
 58	    if (!items.length) {
 59	      console.error('updateTourItems called while items = ', items);
 60	    }
 61	  };
 62	
 63	  const addOnIndexChangeListener = (fn: IndexChangeFunction) => {
 64	    onIndexChangeFunctions.push(fn);
 65	  };
 66	
 67	  const clearOnIndexChangeListener = () => {
 68	    onIndexChangeFunctions.splice(0);
 69	  };
 70	
 71	  const clearIndex = React.useCallback(() => {
 72	    setIndex(undefined);
 73	    clearHighlights();
 74	  }, [clearHighlights]);
 75	
 76	  const previous = React.useCallback(() => {
 77	    if (index) {
 78	      setIndex(index - 1);
 79	    } else {
 80	      clearIndex();
 81	    }
 82	  }, [clearIndex, index]);
 83	
 84	  const hasNext = React.useCallback(() => {
 85	    return index != undefined && index < items.length - 1;
 86	  }, [index, items.length]);
 87	
 88	  const next = React.useCallback(() => {
 89	    if (hasNext()) {
 90	      setIndex(index! + 1);
 91	    } else {
 92	      clearIndex();
 93	    }
 94	  }, [clearIndex, hasNext, index]);
 95	
 96	  const handleHighlights = React.useCallback(() => {
 97	    if (index != undefined && items.length > index && items[index].ref.current) {
 98	      highlightElement(items[index].ref.current!);
 99	    } else {
100	      clearHighlights();
101	    }
102	  }, [clearHighlights, highlightElement, index, items]);
103	
104	  React.useEffect(() => {
105	    onIndexChangeFunctions.forEach(fn => {
106	      fn(index);
107	    });
108	
109	    handleHighlights();
110	  }, [highlightElement, index, items, clearHighlights, handleHighlights]);
111	
112	  React.useEffect(() => {
113	    window.addEventListener('resize', handleHighlights);
114	    return () => {
115	      window.removeEventListener('resize', handleHighlights);
116	    };
117	  }, [handleHighlights]);
118	
119	  let currentItem = undefined;
120	  if (index !== undefined) {
121	    currentItem = items[index];
122	  }
123	  return currentItem ? (
124	    <Popover
125	      id={`${props.id}-tour-popover`}
126	      isVisible={index !== undefined}
127	      position={currentItem!.position ? currentItem.position : undefined}
128	      hideOnOutsideClick={false}
129	      showClose={false}
130	      minWidth={currentItem!.minWidth ? currentItem!.minWidth : undefined}
131	      headerContent={
132	        <Flex direction={{ default: 'row' }}>
133	          <FlexItem flex={{ default: 'flex_1' }}>{currentItem!.title}</FlexItem>
134	          <FlexItem>
135	            <Button
136	              icon={<TimesIcon />}
137	              variant="plain"
138	              className="guided-tour-close-button"
139	              onClick={() => clearIndex()}
140	            />
141	          </FlexItem>
142	        </Flex>
143	      }
144	      bodyContent={
145	        <Flex direction={{ default: 'column' }}>
146	          <FlexItem flex={{ default: 'flex_1' }}>{currentItem!.description}</FlexItem>
147	          <FlexItem>
148	            {currentItem!.assetName && (
149	              <img
150	                src={`${isStandalone ? '/assets/' : '/api/plugins/netobserv-plugin/assets/'}${currentItem.assetName}`}
151	              />
152	            )}
153	          </FlexItem>
154	        </Flex>
155	      }
156	      footerContent={
157	        <Flex direction={{ default: 'row' }}>
158	          <FlexItem flex={{ default: 'flex_1' }}>
159	            <Text component={TextVariants.p} className="text-muted">
160	              {t('Step {{step}}/{{total}}', { step: (index || 0) + 1, total: items.length })}
161	            </Text>
162	          </FlexItem>
163	          <FlexItem>
164	            {index ? (
165	              <Button variant="secondary" className="guided-tour-tips-button" onClick={() => previous()}>
166	                {t('Previous tip')}
167	              </Button>
168	            ) : (
169	              <></>
170	            )}
171	          </FlexItem>
172	          <FlexItem>
173	            <Button variant="primary" className="guided-tour-tips-button" onClick={() => next()}>
174	              {hasNext() ? t('Next tip') : t('Close tips')}
175	            </Button>
176	          </FlexItem>
177	        </Flex>
178	      }
179	      triggerRef={currentItem!.ref}
180	    />
181	  ) : null;
182	});
183	
184	export default GuidedTourPopover;

